sql:
SELECT month, spontaneous_brand_awareness, brand_consideration
FROM brand_metrics
WHERE product_id = 0;

SELECT category_id, AVG(overall_awareness) AS avg_awareness, MIN(overall_consideration) AS min_consideration
FROM brand_performance
GROUP BY category_id;

SELECT AVG(spontaneous_brand_awareness + brand_consideration) AS avg_brand_engagement
FROM brand_metrics
WHERE month = '2023-09';

SELECT overall_awareness 
FROM brand_performance 
WHERE date BETWEEN '2017-07-01' AND '2017-08-31';

SELECT month, spontaneous_brand_awareness
FROM brand_metrics
ORDER BY month;

SELECT AVG(overall_awareness) AS avg_awareness, AVG(overall_consideration) AS avg_consideration
FROM brand_performance
WHERE category_id = 1;

SELECT category_name
FROM brand_categories
WHERE category_name = 'Fibre Products';

external_knowledge:
Active campaign: refers to a campaign with a 'campaign_status' of 'active'; 
Last quarter: refers to the period between date('now', '-3 months') and date('now'); 
At least two data points: ensures that the averages are calculated from a meaningful number of data points.

sql:
SELECT category_name, COUNT(*) AS category_entry_count
FROM brand_categories
GROUP BY category_name;

SELECT COUNT(DISTINCT metric_id) AS unique_metrics
FROM brand_metrics
WHERE month = '2017-07';
